<h1>Applications for <?= e($requisition['title']) ?></h1>
<table><thead><tr><th>Candidate</th><th>Status</th><th>Match</th><th>Update</th></tr></thead><tbody>
<?php foreach ($applications as $application): ?><tr><td><?= e($application['name']) ?><br><span class="muted"><?= e($application['email']) ?></span></td><td><?= e($application['status']) ?></td><td><?= e($application['match_score']) ?>%</td><td><form method="POST" action="<?= e(url('hr.applications.update', [$application['application_id']])) ?>"><?= csrf_field() ?><?= method_field('PUT') ?><select name="status"><?php foreach (['APPLIED','SCREENING','ASSESSMENT','INTERVIEW','OFFER','REJECTED','HIRED'] as $status): ?><option value="<?= e($status) ?>"<?= selected($application['status'], $status) ?>><?= e($status) ?></option><?php endforeach; ?></select><input name="reason" placeholder="Reason"><button type="submit">Update</button></form></td></tr><?php endforeach; ?>
</tbody></table>
